class Solution {
public:
    int countBinarySubstrings(string s) {
        int res = 0;
        int prev = 0, curr = 1;
        for (int i = 1; i < s.size(); i++) {
            if (s[i] != s[i - 1]) {
                res += min(prev, curr);
                prev = curr;
                curr = 1;
            } else {
                curr++;
            }
        }
        return res + min(prev, curr);
    }
};
```
